def svg_icon(name: str, color: str = "currentColor", size: int = 24) -> str:
    svg = ICONS.get(name, ICONS["chat"])
    return svg.replace("currentColor", color).replace(
        'viewBox="0 0 24 24"', f'viewBox="0 0 24 24" width="{size}" height="{size}"'
    )
